function f(r,e=2){if(r==null)return"\u2014";let t=1e12,i=1e9,n=1e6,u=1e3;return r>=t?`${(r/t).toFixed(e)} TB`:r>=i?`${(r/i).toFixed(Math.min(e,1))} GB`:r>=n?`${(r/n).toFixed(0)} MB`:r>=u?`${(r/u).toFixed(0)} KB`:`${r} B`}function B(r,e=2){if(r===0)return"0 B";let t=Math.abs(r);return t>=1e15?(r/1e15).toFixed(e)+" PB":t>=1e12?(r/1e12).toFixed(e)+" TB":t>=1e9?(r/1e9).toFixed(e)+" GB":t>=1e6?(r/1e6).toFixed(e)+" MB":t>=1e3?(r/1e3).toFixed(e)+" KB":r.toFixed(e)+" B"}function x(r){if(r===0)return"0";let e=Math.abs(r),t=r<0?"-":"";return e>=1e15?t+(e/1e15).toFixed(1)+"P":e>=1e12?t+(e/1e12).toFixed(1)+"T":e>=1e9?t+(e/1e9).toFixed(1)+"G":e>=1e6?t+(e/1e6).toFixed(1)+"M":e>=1e3?t+(e/1e3).toFixed(1)+"K":t+e.toFixed(0)+"B"}function d(r){let e=Math.max(...r.map(Math.abs));return e>=1e15?{divisor:1e15,unit:"PB"}:e>=1e12?{divisor:1e12,unit:"TB"}:e>=1e9?{divisor:1e9,unit:"GB"}:e>=1e6?{divisor:1e6,unit:"MB"}:e>=1e3?{divisor:1e3,unit:"KB"}:{divisor:1,unit:"B"}}function o(r){return r?new Date(r).toLocaleDateString("en-GB",{day:"2-digit",month:"short",year:"numeric"}):"\u2014"}function F(r){return r?o(r*1e3):"\u2014"}export{f as fmt,o as fmtDate,F as fmtDateSec,d as pickUnit,B as smartFmt,x as smartFmtTick};
